```javascript
const SHEET_ID = '1YM0dKPWySifYFDyNqCenJ4L85xIBSTrBGNPDcoo6Kfg';
const SHEET_NAME = 'Master_SKU_Mapping';

// --- MAIN HANDLERS ---

function doGet(e) {
  try {
    const data = getInventoryData();
    return sendJSON({ status: 'success', data: data });
  } catch (error) {
    return sendJSON({ status: 'error', message: error.toString() });
  }
}

function doPost(e) {
  try {
    const params = JSON.parse(e.postData.contents);
    let result;

    if (params.action === 'updatePrice') {
      result = updateSellingPrice(params);
    } else if (params.action === 'createItem') {
      result = createNewItem(params);
    } else {
      result = { status: 'error', message: 'Unknown action' };
    }

    return sendJSON(result);
  } catch (error) {
    return sendJSON({ status: 'error', message: error.toString() });
  }
}

function sendJSON(data) {
  return ContentService.createTextOutput(JSON.stringify(data))
    .setMimeType(ContentService.MimeType.JSON);
}

// --- CORE LOGIC ---

function getInventoryData() {
  const sheet = SpreadsheetApp.openById(SHEET_ID).getSheetByName(SHEET_NAME);
  // Assuming Sheet format based on CSV description:
  // Col A: Channel, B: Article Code, C: Master SKU, D: Selling Price
  // If your sheet has headers, we skip row 1
  const data = sheet.getDataRange().getValues();
  const inventoryList = [];
  const masterSkus = new Set();

  // Start from 1 to skip headers
  for (let i = 1; i < data.length; i++) {
    const row = data[i];
    // Basic validation to skip empty rows
    if (!row[0]) continue; 

    const channel = String(row[0]);
    const articleCode = String(row[1]);
    const masterSku = String(row[2]);
    const spIncTax = Number(row[3]) || 0; // Selling Price

    if (masterSku) masterSkus.add(masterSku);

    inventoryList.push({
      id: channel + '-' + articleCode,
      channel: channel,
      articleCode: articleCode,
      sku: masterSku,
      spIncTax: spIncTax,
      // Default values to be overwritten by EasyEcom
      itemName: 'Fetching...',
      ean: '',
      mrp: 0,
      basicPrice: 0, 
      stock: 0 
    });
  }

  // Fetch details from EasyEcom
  const skuArray = Array.from(masterSkus);
  const eeData = fetchEasyEcomInventory(skuArray);

  // Merge Data
  return inventoryList.map(item => {
    const details = eeData[item.sku];
    if (details) {
      return {
        ...item,
        itemName: details.product_name || item.itemName,
        ean: details.ean || '',
        mrp: details.mrp || 0,
        basicPrice: details.cost_price || 0,
        stock: details.available_qty || 0
      };
    }
    return { ...item, itemName: 'SKU Not Found in EasyEcom' };
  });
}

function updateSellingPrice(params) {
  const sheet = SpreadsheetApp.openById(SHEET_ID).getSheetByName(SHEET_NAME);
  const data = sheet.getDataRange().getValues();

  for (let i = 1; i < data.length; i++) {
    const rowChannel = String(data[i][0]);
    const rowArticle = String(data[i][1]);

    if (rowChannel === params.channel && rowArticle === params.articleCode) {
      // Update Column D (index 3) -> Selling Price
      sheet.getRange(i + 1, 4).setValue(params.newPrice);
      return { status: 'success', message: 'Price updated successfully' };
    }
  }
  return { status: 'error', message: 'Item not found in sheet' };
}

function createNewItem(params) {
  const sheet = SpreadsheetApp.openById(SHEET_ID).getSheetByName(SHEET_NAME);
  const data = sheet.getDataRange().getValues();

  // Check for duplicates
  for (let i = 1; i < data.length; i++) {
    if (String(data[i][0]) === params.channel && String(data[i][1]) === params.articleCode) {
      return { status: 'error', message: 'Mapping already exists for this Channel & Article Code' };
    }
  }

  // Append new row: Channel, Article, Master SKU, Selling Price
  sheet.appendRow([
    params.channel,
    params.articleCode,
    params.sku,
    params.spIncTax
  ]);

  return { status: 'success', message: 'Item created successfully' };
}

// --- EASY ECOM INTEGRATION ---

function getEasyEcomToken() {
  const scriptProperties = PropertiesService.getScriptProperties();
  const url = "https://api.easyecom.io/access/token";

  const payload = {
    email: scriptProperties.getProperty('EASY_ECOM_EMAIL'),
    password: scriptProperties.getProperty('EASY_ECOM_PASSWORD'),
    location_key: scriptProperties.getProperty('EASY_ECOM_LOCATION_KEY')
  };

  const options = {
    method: "post",
    headers: {
      "x-api-key": scriptProperties.getProperty('EASY_ECOM_API_KEY'),
      "Content-Type": "application/json"
    },
    payload: JSON.stringify(payload),
    muteHttpExceptions: true
  };

  try {
    const response = UrlFetchApp.fetch(url, options);
    const result = JSON.parse(response.getContentText());
    if (result.code == 200 && result.data && result.data.token) {
        return result.data.token.jwt_token;
    }
    Logger.log("Token Generation Failed: " + JSON.stringify(result));
    return null;
  } catch (err) {
    Logger.log("Token Error: " + err.message);
    return null;
  }
}

function fetchEasyEcomInventory(skus) {
  const token = getEasyEcomToken();
  if (!token) return {};

  const inventoryMap = {};

  // EasyEcom API to get details. 
  // Ideally, use a bulk endpoint. Since I don't have the exact bulk SKU endpoint docs here,
  // I will use a loop or a standard 'getProductsList' if available. 
  // For reliability in this script, I'll simulate the structure you need using 'Products/getAllProducts'
  // But strictly filtering is better. 

  // Assuming we fetch all or search. 
  // Optimized approach: 
  // If list is huge, this needs pagination. For now, assume < 50 items or we fetch basic list.

  const url = "https://api.easyecom.io/v1/products/getProductsList"; // Generic endpoint
  const options = {
    method: "get",
    headers: { "Authorization": token },
    muteHttpExceptions: true
  };

  try {
    // Note: In a real high-volume scenario, you'd iterate pages or filter by SKU if API supports it.
    const response = UrlFetchApp.fetch(url, options);
    const result = JSON.parse(response.getContentText());

    if (result.code == 200 && result.data) {
      result.data.forEach(product => {
        // Map EasyEcom fields to our app fields
        if(skus.includes(product.product_sku)) {
             inventoryMap[product.product_sku] = {
                product_name: product.product_name || product.name,
                ean: product.ean || '',
                mrp: product.mrp || 0,
                cost_price: product.cost_price || 0,
                available_qty: product.available_qty || 0 // Or inventory_count
            };
        }
      });
    }
  } catch (e) {
    Logger.log("EasyEcom Fetch Error: " + e.toString());
  }

  return inventoryMap;
}
```

