                    <div className="bg-white p-8 rounded-xl shadow-sm text-center">
                        <h3 className="text-lg font-semibold text-gray-700">Welcome to the QuickCommerce Dashboard, {currentUser.name}</h3>
                        <p className="text-gray-500 mt-2">Select a card above to manage specific orders or use the sidebar for navigation.</p>
                    </div>
                </div>
            );
        case 'POC Verification':
            return <PocVerification purchaseOrders={purchaseOrders} setPurchaseOrders={setPurchaseOrders} addLog={addLog} />;
        case 'Appointments':
            return <AppointmentManager purchaseOrders={purchaseOrders} setPurchaseOrders={setPurchaseOrders} addLog={addLog} />;
        case 'Finance':
            return <FinanceManager purchaseOrders={purchaseOrders} setPurchaseOrders={setPurchaseOrders} addLog={addLog} />;
        case 'Inventory':
            return <InventoryManager 
                addLog={addLog} 
                inventoryItems={inventoryItems} 
                setInventoryItems={setInventoryItems}
                onSync={() => refreshData(true)}
                isSyncing={isLoading}
            />;
        case 'Reports':
            return <ReportsManager purchaseOrders={purchaseOrders} inventoryItems={inventoryItems} />;
        case 'Purchase Orders':
        case 'Uploads':
        case 'Shipments':
        case 'GRN / POD':
            return <CommonPoTable />;
        case 'Admin':
            return <AdminPanel 
                        logs={logs} 
                        users={users} 
                        setUsers={setUsers}
                        rolePermissions={rolePermissions}
                        setRolePermissions={setRolePermissions}
                        addLog={addLog}
                        currentUser={currentUser}
                        channelConfigs={channelConfigs}
                        onSync={() => refreshData(true)}
                    />;
        default:
            return <PlaceholderContent view={activeView} />;
    }
  };

  return (
    <div className="flex h-screen bg-partners-gray-bg font-sans">
      {isSidebarOpen && (
        <div 
          className="fixed inset-0 bg-black opacity-50 z-20 lg:hidden" 
          onClick={() => setSidebarOpen(false)}
        ></div>
      )}

      <div className={`fixed lg:relative inset-y-0 left-0 transform ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full'} lg:translate-x-0 transition-transform duration-300 ease-in-out z-30`}>
        <Sidebar 
            activeView={activeView} 
            setActiveView={setActiveView} 
            currentUser={currentUser}
            permissions={rolePermissions}
            onSwitchUser={handleSwitchUser}
            allUsers={users}
        />
      </div>

      <main className="flex-1 flex flex-col overflow-y-auto">
        <div className="flex items-center justify-between p-4 lg:hidden">
            <button onClick={() => setSidebarOpen(!isSidebarOpen)} className="text-gray-500 focus:outline-none">
              {isSidebarOpen ? <XIcon /> : <MenuIcon />}
            </button>
             {/* Mobile Header for Notifications if sidebar is closed */}
             <div className="ml-auto">
                <Header 
                    notifications={notifications} 
                    onMarkRead={markNotificationRead} 
                    onClearAll={clearAllNotifications} 
                    onViewLogs={() => setActiveView('Admin')}
                />
             </div>
        </div>

        {renderContent()}

      </main>

       <button className="fixed bottom-6 right-6 bg-green-600 text-white p-3 rounded-full shadow-lg hover:bg-green-700 transition-colors flex items-center gap-2 z-40">
          <QuestionMarkCircleIcon />
          <span className="font-semibold">Help</span>
        </button>
