                                <th scope="col" className="px-6 py-3 whitespace-nowrap">Order Date <SortIcon className="inline-block ml-1 text-gray-400"/></th>
                                <th scope="col" className="px-6 py-3 whitespace-nowrap">Stock Status</th>
                                <th scope="col" className="px-6 py-3 whitespace-nowrap">Action to be Taken</th>
                                <th scope="col" className="px-6 py-3">Actions</th>
                            </tr>
                        </thead>
                        <tbody>
                            {filteredOrders.length === 0 ? (
                                <tr>
                                    <td colSpan={11} className="px-6 py-8 text-center text-gray-500">
                                        No purchase orders found matching your filters.
                                    </td>
                                </tr>
                            ) : (
                                filteredOrders.map((po) => {
                                    const stockStatus = getStockStatus(po);
                                    const isExpanded = expandedRowId === po.id;
                                    const hasCostError = hasCostMismatch(po);

                                    return (
                                    <Fragment key={po.id}>
                                        <tr className={`border-b hover:bg-gray-50 transition-colors ${isExpanded ? 'bg-gray-50' : 'bg-white'}`}>
