const transformSheetDataToInventory = (rows: any[]): InventoryItem[] => {
    return rows.map((row, index) => {
        // Headers provided: Channel, Channel Item Code, Master SKU, Selling Price, Inventory, EAN, Itemname, MRP
        return {
            id: `inv-${index}-${Date.now()}`,
            channel: row['Channel'] || 'Unknown',
            articleCode: String(row['Channel Item Code'] || row['articleCode'] || ''),
            sku: String(row['Master SKU'] || row['sku'] || ''),
            ean: String(row['EAN'] || ''),
            itemName: row['Itemname'] || row['ItemName'] || row['Item Name'] || '', 
            mrp: Number(row['MRP'] || 0),
            basicPrice: 0, 
            spIncTax: Number(row['Selling Price'] || 0),
            stock: Number(row['Inventory'] || 0)
        };
    });
};

// Helper to format date consistently
const formatSheetDate = (dateVal: any): string => {
    if (!dateVal) return new Date().toLocaleDateString('en-GB', { day: 'numeric', month: 'short', year: 'numeric' });

    // Check if it's already a clean string like "12 Oct 2025" or "12/10/2025"
    if (typeof dateVal === 'string' && dateVal.length < 15 && !dateVal.includes('T')) {
        return dateVal;
    }

    const d = new Date(dateVal);
    if (isNaN(d.getTime())) return String(dateVal);

    return d.toLocaleDateString('en-GB', { day: 'numeric', month: 'short', year: 'numeric' });
};

const transformSheetDataToPOs = (rows: any[]): PurchaseOrder[] => {
    const poMap = new Map<string, PurchaseOrder>();

    rows.forEach((row) => {
        // Map keys based on likely Google Sheet Headers (handling variations)
        const poNumber = row['PO Number'] || row['PO_Number'] || row['poNumber'];
        if (!poNumber) return;

        const rawStatus = row['Status'] || 'New';
        let status = POStatus.NewPO;

        // Map Sheet Status to Enum
        if (rawStatus === 'Below Threshold') status = POStatus.BelowThreshold;
        else if (rawStatus === 'New') status = POStatus.NewPO;
        else if (Object.values(POStatus).includes(rawStatus as POStatus)) status = rawStatus as POStatus;

        // Robust parsing for Quantity and new Fulfillable Qty
        const qty = Number(row['Qty'] || row['qty'] || row['Quantity'] || 0);
        const fulfillableQty = Number(row['Fulfillable qty'] || row['fulfillable qty'] || 0);

        const unitCost = Number(row['Unit Cost (Tax Exclusive)'] || row['Unit Cost'] || 0);
        const mrp = Number(row['MRP'] || 0);
        const itemAmount = qty * unitCost;

        const item: POItem = {
            articleCode: String(row['Item Code'] || ''),
            masterSku: String(row['Master SKU'] || ''),
            itemName: row['Item Name'] || '',
            qty: qty,
            fulfillableQty: fulfillableQty,
            unitCost: unitCost,
            mrp: mrp
        };

        if (poMap.has(poNumber)) {
            const po = poMap.get(poNumber)!;
            po.items?.push(item);
            po.qty += qty;
            po.amount += itemAmount;
        } else {
            const newPO: PurchaseOrder = {
                id: poNumber,
                poNumber: poNumber,
                status: status,
                channel: row['Channel Name'] || 'Unknown',
                storeCode: row['Store Code'] || '',
                qty: qty,
                amount: itemAmount,
                orderDate: formatSheetDate(row['PO Date']),
                poEdd: row['PO EDD'] ? formatSheetDate(row['PO EDD']) : undefined,
                poExpiryDate: row['PO Expiry Date'] ? formatSheetDate(row['PO Expiry Date']) : undefined,
                source: 'API',
                items: [item],
                poPdfUrl: row['PO PDF'] || undefined,
                contactVerified: false,
                actionToBeTaken: status === POStatus.NewPO ? 'Upload PO PDF' : 'Review',
                amountReceived: 0,
            };

            // Smart Actions based on data presence
            if (newPO.poPdfUrl && newPO.status === POStatus.NewPO) {
                // If PDF is already linked in sheet, maybe move to next step or mark as ready
                 newPO.actionToBeTaken = 'Verify POC';
            }
            if (newPO.status === POStatus.BelowThreshold) {
                newPO.actionToBeTaken = 'Review Threshold';
            }

            poMap.set(poNumber, newPO);
        }
    });

    return Array.from(poMap.values());
};

const transformSheetDataToChannelConfigs = (rows: any[]): ChannelConfig[] => {
    return rows.map((row) => ({
        id: row['Channel Name'] || 'unknown',
        channelName: row['Channel Name'] || '',
        status: row['Status'] === 'Active' ? 'Active' : 'Inactive',
        sourceEmail: row['Source Email'] || '',
        searchKeyword: row['Search Keyword'] || '',
        minOrderThreshold: Number(row['Min Order Threshold'] || 0),
        pocName: row['POC Name'] || '',
        pocEmail: row['POC Email'] || '',
        pocPhone: row['POC Phone'] || '',
    }));
};

