import React, { useState, useMemo, useEffect, useCallback } from 'react';
import Sidebar from './components/Sidebar';
import Header from './components/Header';
import SummaryCard from './components/SummaryCard';
import PoTable from './components/PoTable';
import PocVerification from './components/PocVerification';
import AppointmentManager from './components/AppointmentManager';
import AdminPanel from './components/AdminPanel';
import FinanceManager from './components/FinanceManager';
import InventoryManager from './components/InventoryManager';
import ReportsManager from './components/ReportsManager';
import { MenuIcon, XIcon, QuestionMarkCircleIcon, RefreshIcon } from './components/icons/Icons';
import { initialUsers, initialRolePermissions } from './data/mockData';
import { type PurchaseOrder, POStatus, ActivityLog, NotificationItem, ViewType, User, RolePermissions, InventoryItem, ChannelConfig, CostPriceItem } from './types';
import { fetchPurchaseOrders, fetchInventoryFromSheet, fetchChannelConfigs, fetchCostPrices } from './services/api';

const App: React.FC = () => {
  const [isSidebarOpen, setSidebarOpen] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [lastSynced, setLastSynced] = useState<number>(0);

  // User & Permission State
  const [users, setUsers] = useState<User[]>(initialUsers);
  const [currentUser, setCurrentUser] = useState<User>(initialUsers[0]); // Default to Admin
  const [rolePermissions, setRolePermissions] = useState<RolePermissions>(initialRolePermissions);

  const [activeView, setActiveView] = useState<ViewType>('Dashboard');
  const [activeFilter, setActiveFilter] = useState('All POs');

  // Data State
  const [purchaseOrders, setPurchaseOrders] = useState<PurchaseOrder[]>([]);
  const [inventoryItems, setInventoryItems] = useState<InventoryItem[]>([]);
  const [channelConfigs, setChannelConfigs] = useState<ChannelConfig[]>([]);
  const [costPrices, setCostPrices] = useState<CostPriceItem[]>([]);

  // State for Logs and Notifications
  const [logs, setLogs] = useState<ActivityLog[]>([
    { id: '1', user: 'System', action: 'Init', details: 'System initialized', timestamp: new Date().toLocaleString() }
  ]);
  const [notifications, setNotifications] = useState<NotificationItem[]>([
      { id: 'init-1', message: 'Welcome to the PO Dashboard', timestamp: 'Just now', read: false, type: 'info' }
  ]);

  // Helper to add logs
  const addLog = useCallback((action: string, details: string) => {
    const newLog: ActivityLog = {
        id: Date.now().toString() + Math.random().toString(36).substring(7),
        user: currentUser.name, 
        action,
        details,
        timestamp: new Date().toLocaleString()
    };
    setLogs(prev => [newLog, ...prev]);
  }, [currentUser]);

  // Helper to add notifications
  const addNotification = useCallback((message: string, type: 'info' | 'success' | 'warning' | 'error' = 'info') => {
    const newNotification: NotificationItem = {
        id: Date.now().toString() + Math.random().toString(36).substring(7),
        message,
        timestamp: 'Just now',
        read: false,
        type
    };
    setNotifications(prev => [newNotification, ...prev]);
  }, []);

  // Core Data Fetching Function
  const refreshData = useCallback(async (force = false) => {
      // 30 minute cache check (30 * 60 * 1000 ms)
      // If not forced and data exists and sync was recent, skip fetch
      if (!force && purchaseOrders.length > 0 && Date.now() - lastSynced < 1800000) {
          console.log("Using cached data. No API call.");
          return; 
      }

      setIsLoading(true);
      try {
          // Parallel Fetch: POs, Inventory, Channel Configs, and Cost Prices
          const [poData, invData, channelData, costData] = await Promise.all([
              fetchPurchaseOrders(),
              fetchInventoryFromSheet(),
              fetchChannelConfigs(),
              fetchCostPrices()
          ]);

          if (poData.length > 0) {
              setPurchaseOrders(poData);
              addLog('Data Sync', `Fetched ${poData.length} orders from Google Sheet.`);
          } else {
               addLog('Data Sync', 'No PO data returned from Sheet or API error.');
          }

          if (invData.length > 0) {
              setInventoryItems(invData);
              addLog('Data Sync', `Fetched ${invData.length} inventory items.`);
          }

          if (channelData.length > 0) {
              setChannelConfigs(channelData);
              addLog('Data Sync', `Fetched ${channelData.length} channel configs.`);
          }

          if (costData.length > 0) {
              setCostPrices(costData);
              addLog('Data Sync', `Fetched ${costData.length} cost prices.`);
          }

          setLastSynced(Date.now());

      } catch (e) {
          console.error("Data Load Error", e);
          addLog('Error', 'Failed to load data from backend.');
          addNotification('Failed to sync data from Google Sheets.', 'error');
      } finally {
          setIsLoading(false);
      }
  }, [addLog, addNotification, lastSynced, purchaseOrders.length]);

  // Initial Load & Auto-Sync Interval
  useEffect(() => {
    // Initial fetch
    refreshData();

    // Set up 30-minute auto-refresh interval
    const intervalId = setInterval(() => {
        refreshData(true); // Force refresh every 30 mins
    }, 30 * 60 * 1000);

    return () => clearInterval(intervalId);
  }, [refreshData]);

  const markNotificationRead = (id: string) => {
      setNotifications(prev => prev.map(n => n.id === id ? { ...n, read: true } : n));
  };

  const clearAllNotifications = () => {
      setNotifications([]);
  };

  const handleSwitchUser = (userId: string) => {
      const newUser = users.find(u => u.id === userId);
      if (newUser) {
          setCurrentUser(newUser);
          setActiveView('Dashboard'); // Reset view on switch
          addLog('User Switch', `Switched to user ${newUser.name} (${newUser.role})`);
      }
  };

  const summaryData = useMemo(() => {
    const totalActive = purchaseOrders.filter(p => p.status !== POStatus.Closed).length;
    const belowThreshold = purchaseOrders.filter(p => p.status === POStatus.BelowThreshold).length;
    const missingPdfs = purchaseOrders.filter(p => p.status === POStatus.NewPO && !p.poPdfUrl).length; // Check URL existence
    const pocsPending = purchaseOrders.filter(p => p.status === POStatus.POCPending).length;
    const awaitingAppointment = purchaseOrders.filter(p => p.status === POStatus.AppointmentPending).length;
    const inTransit = purchaseOrders.filter(p => p.status === POStatus.InTransit).length;
    const rtoShipments = purchaseOrders.filter(p => p.status === POStatus.RTO).length;
    const closedShipments = purchaseOrders.filter(p => p.status === POStatus.Closed).length;

    return [
      { title: 'Total Active POs', value: totalActive.toString(), change: 'across all stages', color: 'green', targetView: 'Purchase Orders', targetFilter: 'All POs' },
      { title: 'Below Threshold', value: belowThreshold.toString(), change: 'low value orders', color: 'yellow', targetView: 'Purchase Orders', targetFilter: 'Below Threshold' },
      { title: 'POCs Pending', value: pocsPending.toString(), change: 'verification needed', color: 'yellow', targetView: 'POC Verification', targetFilter: '' },
      { title: 'Awaiting Appointment', value: awaitingAppointment.toString(), change: 'follow-up required', color: 'yellow', targetView: 'Appointments', targetFilter: '' },
      { title: 'Shipments In Transit', value: inTransit.toString(), change: 'currently shipping', color: 'blue', targetView: 'Shipments', targetFilter: 'In-Transit' },
      { title: 'RTO Shipments', value: rtoShipments.toString(), change: 'in last 30 days', color: 'red', targetView: 'Shipments', targetFilter: 'RTO' },
      { title: 'Closed Shipments', value: closedShipments.toString(), change: 'in last 30 days', color: 'green', targetView: 'Shipments', targetFilter: 'Closed' },
    ];
  }, [purchaseOrders]);

  const tabCounts = useMemo(() => {
    const statusToTabMap: { [key in POStatus]?: string } = {
        [POStatus.NewPO]: 'New PO',
        [POStatus.BelowThreshold]: 'Below Threshold',
        [POStatus.POCPending]: 'POC Verification',
        [POStatus.AppointmentPending]: 'Appointment to be taken',
        [POStatus.InTransit]: 'In-Transit',
        [POStatus.GRNPending]: 'GRN Pending',
        [POStatus.GRNUpdated]: 'GRN Updated',
        [POStatus.RTO]: 'RTO',
        [POStatus.Closed]: 'Closed',
    };

    const initialCounts = Object.values(statusToTabMap).reduce((acc, tabName) => {
        if(tabName) acc[tabName] = 0;
        return acc;
    }, {} as { [key: string]: number });

    const countsByStatus = purchaseOrders.reduce((acc, po) => {
        const tabName = statusToTabMap[po.status];
        if (tabName) {
            acc[tabName] = (acc[tabName] || 0) + 1;
        }
        return acc;
    }, initialCounts);

    return {
        'All POs': purchaseOrders.length,
        ...countsByStatus
    };
  }, [purchaseOrders]);

  const handleCardClick = (view: ViewType, filter?: string) => {
      // Check permissions before navigation
      if (rolePermissions[currentUser.role]?.includes(view)) {
          setActiveView(view);
          if (filter) {
              setActiveFilter(filter);
          }
      } else {
          addNotification(`Access Denied: You do not have permission to view ${view}.`, 'error');
      }
  };

  const PlaceholderContent: React.FC<{view: string}> = ({ view }) => (
    <div className="flex-1 flex items-center justify-center text-center p-8">
        <div>
            <h1 className="text-3xl font-bold text-gray-700">{view}</h1>
            <p className="mt-2 text-gray-500">Functionality for this section is under construction.</p>
        </div>
    </div>
  );

  const renderContent = () => {
    // Only show full screen loader on initial load if no data
    if (isLoading && purchaseOrders.length === 0) {
        return (
            <div className="flex-1 flex flex-col items-center justify-center">
                <RefreshIcon className="h-10 w-10 text-partners-green animate-spin mb-4" />
                <p className="text-gray-600 font-medium">Fetching Data from Google Sheet...</p>
            </div>
        );
    }

    const CommonPoTable = () => (
        <div className="p-4 sm:p-6 lg:p-8 flex-1">
            <h1 className="text-2xl font-bold text-gray-800 mb-6">{activeView}</h1>
            <PoTable 
                activeFilter={activeFilter} 
                setActiveFilter={setActiveFilter} 
                purchaseOrders={purchaseOrders}
                setPurchaseOrders={setPurchaseOrders}
                tabCounts={tabCounts}
                addLog={addLog}
                addNotification={addNotification}
                inventoryItems={inventoryItems}
                costPrices={costPrices}
                onSync={() => refreshData(true)}
                isSyncing={isLoading}
            />
        </div>
    );

    switch (activeView) {
        case 'Dashboard':
            return (
                <div className="p-4 sm:p-6 lg:p-8 flex-1">
                    <Header 
                        notifications={notifications} 
                        onMarkRead={markNotificationRead} 
                        onClearAll={clearAllNotifications} 
                        onViewLogs={() => setActiveView('Admin')}
                    />
                    <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 2xl:grid-cols-7 gap-6 my-6">
                        {summaryData.map((card, index) => (
                            <SummaryCard
                                key={index}
                                title={card.title}
                                value={card.value}
                                changeText={card.change}
                                color={card.color as 'green' | 'red' | 'yellow' | 'blue'}
                                onClick={() => handleCardClick(card.targetView as ViewType, card.targetFilter)}
                            />
                        ))}
                    </div>
                    <div className="bg-white p-8 rounded-xl shadow-sm text-center">
                        <h3 className="text-lg font-semibold text-gray-700">Welcome to the QuickCommerce Dashboard, {currentUser.name}</h3>
                        <p className="text-gray-500 mt-2">Select a card above to manage specific orders or use the sidebar for navigation.</p>
                    </div>
                </div>
            );
        case 'POC Verification':
            return <PocVerification purchaseOrders={purchaseOrders} setPurchaseOrders={setPurchaseOrders} addLog={addLog} />;
        case 'Appointments':
            return <AppointmentManager purchaseOrders={purchaseOrders} setPurchaseOrders={setPurchaseOrders} addLog={addLog} />;
        case 'Finance':
            return <FinanceManager purchaseOrders={purchaseOrders} setPurchaseOrders={setPurchaseOrders} addLog={addLog} />;
        case 'Inventory':
            return <InventoryManager 
                addLog={addLog} 
                inventoryItems={inventoryItems} 
                setInventoryItems={setInventoryItems}
                onSync={() => refreshData(true)}
                isSyncing={isLoading}
            />;
        case 'Reports':
            return <ReportsManager purchaseOrders={purchaseOrders} inventoryItems={inventoryItems} />;
        case 'Purchase Orders':
        case 'Uploads':
        case 'Shipments':
        case 'GRN / POD':
            return <CommonPoTable />;
        case 'Admin':
            return <AdminPanel 
                        logs={logs} 
                        users={users} 
                        setUsers={setUsers}
                        rolePermissions={rolePermissions}
                        setRolePermissions={setRolePermissions}
                        addLog={addLog}
                        currentUser={currentUser}
                        channelConfigs={channelConfigs}
                        onSync={() => refreshData(true)}
                    />;
        default:
            return <PlaceholderContent view={activeView} />;
    }
  };

  return (
    <div className="flex h-screen bg-partners-gray-bg font-sans">
      {isSidebarOpen && (
        <div 
          className="fixed inset-0 bg-black opacity-50 z-20 lg:hidden" 
          onClick={() => setSidebarOpen(false)}
        ></div>
      )}

      <div className={`fixed lg:relative inset-y-0 left-0 transform ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full'} lg:translate-x-0 transition-transform duration-300 ease-in-out z-30`}>
        <Sidebar 
            activeView={activeView} 
            setActiveView={setActiveView} 
            currentUser={currentUser}
            permissions={rolePermissions}
            onSwitchUser={handleSwitchUser}
            allUsers={users}
        />
      </div>

      <main className="flex-1 flex flex-col overflow-y-auto">
        <div className="flex items-center justify-between p-4 lg:hidden">
            <button onClick={() => setSidebarOpen(!isSidebarOpen)} className="text-gray-500 focus:outline-none">
              {isSidebarOpen ? <XIcon /> : <MenuIcon />}
            </button>
             {/* Mobile Header for Notifications if sidebar is closed */}
             <div className="ml-auto">
                <Header 
                    notifications={notifications} 
                    onMarkRead={markNotificationRead} 
                    onClearAll={clearAllNotifications} 
                    onViewLogs={() => setActiveView('Admin')}
                />
             </div>
        </div>

        {renderContent()}

      </main>

       <button className="fixed bottom-6 right-6 bg-green-600 text-white p-3 rounded-full shadow-lg hover:bg-green-700 transition-colors flex items-center gap-2 z-40">
          <QuestionMarkCircleIcon />
          <span className="font-semibold">Help</span>
        </button>
    </div>
  );
};

