function getCostPrices() {
  // External Spreadsheet ID and Sheet GID provided by user
  const SPREADSHEET_ID = '1YM0dKPWySifYFDyNqCenJ4L85xIBSTrBGNPDcoo6Kfg';
  const SHEET_GID = 1695352288;

  try {
