// --- Data Modification Functions ---

function createInventoryItem(data) {
  const sheet = SpreadsheetApp.getActiveSpreadsheet().getSheetByName(SHEET_INVENTORY);
  if (!sheet) return responseJSON({status: 'error', message: 'Sheet "' + SHEET_INVENTORY + '" not found.'});

  // Header definition based on user requirement:
  // Channel, Channel Item Code, Master SKU, Selling Price, Inventory, EAN, Itemname, MRP

  sheet.appendRow([
    data.channel,
    data.articleCode, // Maps to Channel Item Code
    data.sku,         // Maps to Master SKU
    data.spIncTax || 0, // Maps to Selling Price
    data.stock || 0,    // Maps to Inventory
    data.ean || '',
    data.itemName || '', // Maps to Itemname
    data.mrp || 0
  ]);

  return responseJSON({status: 'success', message: 'Item created'});
}

function updateInventoryPrice(data) {
  const sheet = SpreadsheetApp.getActiveSpreadsheet().getSheetByName(SHEET_INVENTORY);
  if (!sheet) return responseJSON({status: 'error', message: 'Sheet "' + SHEET_INVENTORY + '" not found.'});

  const rows = sheet.getDataRange().getValues();
  if (rows.length < 1) return responseJSON({status: 'error', message: 'Sheet is empty'});

  const headers = rows[0].map(h => String(h).toLowerCase().trim());

  // Find column indexes based on specific headers provided
  const colChannel = headers.indexOf('channel');

  // Try exact match first, then fallback to partial
  let colArticle = headers.indexOf('channel item code');
  if (colArticle === -1) colArticle = headers.findIndex(h => h.includes('item code') || h.includes('article'));

  let colPrice = headers.indexOf('selling price');
  if (colPrice === -1) colPrice = headers.findIndex(h => h.includes('selling') || h.includes('sp'));

  if (colChannel === -1 || colArticle === -1 || colPrice === -1) {
    return responseJSON({
      status: 'error', 
      message: `Required columns not found. Found: ${headers.join(', ')}. Need: Channel, Channel Item Code, Selling Price`
    });
  }

  // Find row to update
  for (let i = 1; i < rows.length; i++) {
    const rowChannel = String(rows[i][colChannel]).trim();
    const rowArticle = String(rows[i][colArticle]).trim();

    // Loose comparison for strings/numbers
    if (rowChannel.toLowerCase() === data.channel.toLowerCase() && rowArticle === String(data.articleCode)) {
      // Update the cell (i + 1 because rows are 0-indexed but Sheets API is 1-indexed)
      sheet.getRange(i + 1, colPrice + 1).setValue(data.newPrice);
      return responseJSON({status: 'success', message: 'Price updated'});
    }
  }

  return responseJSON({status: 'error', message: 'Item not found in Inventory sheet'});
}

function saveChannelConfig(data) {
  const sheet = SpreadsheetApp.getActiveSpreadsheet().getSheetByName(SHEET_CHANNEL_CONFIG);
  if (!sheet) return responseJSON({status: 'error', message: `Sheet "${SHEET_CHANNEL_CONFIG}" not found.`});

  const rows = sheet.getDataRange().getValues();
  if (rows.length === 0) return responseJSON({status: 'error', message: 'Sheet is empty, add headers first.'});

  const headers = rows[0].map(h => String(h).toLowerCase().trim());

  const nameIdx = headers.indexOf('channel name');
  if (nameIdx === -1) return responseJSON({status: 'error', message: 'Header "Channel Name" not found.'});

  let rowIndex = -1;
  // Try to find existing
  for (let i = 1; i < rows.length; i++) {
    if (String(rows[i][nameIdx]).toLowerCase() === data.channelName.toLowerCase()) {
      rowIndex = i + 1; // 1-based
      break;
    }
  }

  // Helper to find col index safely
  const getCol = (name) => {
    const idx = headers.findIndex(h => h === name.toLowerCase());
    return idx === -1 ? -1 : idx + 1;
  };

  const colStatus = getCol('Status');
  const colEmail = getCol('Source Email');
  const colKeyword = getCol('Search Keyword');
  const colThreshold = getCol('Min Order Threshold');
  const colPocName = getCol('POC Name');
  const colPocEmail = getCol('POC Email');
  const colPocPhone = getCol('POC Phone');

  if (rowIndex > 0) {
    // Update
    if (colStatus > 0) sheet.getRange(rowIndex, colStatus).setValue(data.status);
    if (colEmail > 0) sheet.getRange(rowIndex, colEmail).setValue(data.sourceEmail);
    if (colKeyword > 0) sheet.getRange(rowIndex, colKeyword).setValue(data.searchKeyword);
    if (colThreshold > 0) sheet.getRange(rowIndex, colThreshold).setValue(data.minOrderThreshold);
    if (colPocName > 0) sheet.getRange(rowIndex, colPocName).setValue(data.pocName);
    if (colPocEmail > 0) sheet.getRange(rowIndex, colPocEmail).setValue(data.pocEmail);
    if (colPocPhone > 0) sheet.getRange(rowIndex, colPocPhone).setValue(data.pocPhone);
    return responseJSON({status: 'success', message: 'Channel updated'});
  } else {
    // Create (Append)
    const newRow = new Array(headers.length).fill('');
    if (nameIdx > -1) newRow[nameIdx] = data.channelName;
    if (colStatus > -1) newRow[colStatus-1] = data.status;
    if (colEmail > -1) newRow[colEmail-1] = data.sourceEmail;
    if (colKeyword > -1) newRow[colKeyword-1] = data.searchKeyword;
    if (colThreshold > -1) newRow[colThreshold-1] = data.minOrderThreshold;
    if (colPocName > -1) newRow[colPocName-1] = data.pocName;
    if (colPocEmail > -1) newRow[colPocEmail-1] = data.pocEmail;
    if (colPocPhone > -1) newRow[colPocPhone-1] = data.pocPhone;

    sheet.appendRow(newRow);
    return responseJSON({status: 'success', message: 'Channel created'});
  }
}

// --- Helpers ---

function getDataAsJSON(sheet) {
  const rawData = sheet.getDataRange().getValues();
  if (rawData.length === 0) return [];

  const headers = rawData[0];
  const data = [];

  for (let i = 1; i < rawData.length; i++) {
    const row = rawData[i];
    // Skip empty rows (check first 2 columns)
    if (row[0] === "" && row[1] === "") continue;

    const obj = {};
    for (let j = 0; j < headers.length; j++) {
      // Use header as key
      obj[headers[j]] = row[j];
    }
    data.push(obj);
  }

  return data;
}

function responseJSON(data) {
  return ContentService.createTextOutput(JSON.stringify(data))
    .setMimeType(ContentService.MimeType.JSON);
}

