interface FileUploadModalProps {
    po: PurchaseOrder;
    uploadType: 'PO' | 'POD';
    onClose: () => void;
    onUploadSuccess: (updatedPo: PurchaseOrder) => void;
    addLog: (action: string, details: string) => void;
}

const FileUploadModal: React.FC<FileUploadModalProps> = ({ po, uploadType, onClose, onUploadSuccess, addLog }) => {
    const [file, setFile] = useState<File | null>(null);
    const [error, setError] = useState<string | null>(null);
    const [isUploading, setIsUploading] = useState(false);

    const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        if (e.target.files && e.target.files[0]) {
            setFile(e.target.files[0]);
            setError(null);
        }
    };

    const validateFile = () => {
        if (!file) {
            setError('Please select a file to upload.');
            return false;
        }

        const allowedFormats = uploadType === 'PO' 
            ? ['.pdf'] 
            : ['.jpg', '.jpeg', '.png', '.webp'];
        const fileExtension = '.' + file.name.split('.').pop()?.toLowerCase();

        if (!allowedFormats.includes(fileExtension)) {
            setError(`Invalid file format. Please upload one of: ${allowedFormats.join(', ')}`);
            return false;
        }

        const fileNameWithoutExt = file.name.replace(/\.[^/.]+$/, "");
        const targetId = uploadType === 'PO' ? po.poNumber : po.awb;

        if (fileNameWithoutExt !== targetId) {
            setError(`Filename must match the ${uploadType === 'PO' ? 'PO Number' : 'AWB'} (${targetId}).`);
            return false;
        }

        return true;
    };

    const handleUpload = () => {
        if (!validateFile()) return;

        setIsUploading(true);
        // Simulate API call
        setTimeout(() => {
            const updatedPo = {
                ...po,
                ...(uploadType === 'PO' && { poPdfUrl: `path/to/${file?.name}`, actionToBeTaken: 'Verify POC', status: POStatus.POCPending }),
                ...(uploadType === 'POD' && { podImageUrl: `path/to/${file?.name}`, actionToBeTaken: undefined, status: POStatus.Closed }),
            };
            onUploadSuccess(updatedPo);
            addLog('Upload', `Uploaded ${uploadType} document for PO ${po.poNumber}`);
            setIsUploading(false);
            onClose();
        }, 1500);
    };

    return (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50 p-4">
            <div className="bg-white rounded-lg shadow-xl w-full max-w-md">
                <div className="p-6 border-b">
                    <h3 className="text-lg font-semibold text-gray-800">Upload {uploadType} Document</h3>
                    <p className="text-sm text-gray-500 mt-1">For PO Number: <span className="font-bold text-partners-green">{po.poNumber}</span></p>
                </div>
                <div className="p-6">
                    <div className="border-2 border-dashed border-gray-300 rounded-lg p-8 text-center bg-gray-50 hover:border-partners-green transition">
                        <UploadIcon className="mx-auto h-12 w-12 text-gray-400" />
                        <label htmlFor="file-upload" className="mt-4 text-sm font-semibold text-partners-green cursor-pointer">
                            {file ? 'Change file' : 'Select a file'}
                        </label>
                        <input id="file-upload" name="file-upload" type="file" className="sr-only" onChange={handleFileChange} />
                        <p className="mt-1 text-xs text-gray-500">{file ? `Selected: ${file.name}` : 'Drag and drop or click to select.'}</p>
                    </div>
                    {error && (
                         <div className="mt-3 flex items-center text-sm text-red-600">
                            <XCircleIcon className="h-4 w-4 mr-2" />
                            {error}
                        </div>
                    )}
                </div>
                <div className="px-6 py-4 bg-gray-50 flex justify-end gap-3 rounded-b-lg">
                    <button onClick={onClose} className="px-4 py-2 text-sm font-medium text-gray-700 bg-white border border-gray-300 rounded-md hover:bg-gray-50">Cancel</button>
                    <button onClick={handleUpload} disabled={isUploading || !file} className="px-4 py-2 text-sm font-medium text-white bg-partners-green border border-transparent rounded-md hover:bg-green-700 disabled:bg-gray-400 disabled:cursor-not-allowed flex items-center">
                        {isUploading ? 'Uploading...' : 'Upload File'}
                    </button>
                </div>
            </div>
        </div>
    );
};

interface PoTableProps {
    activeFilter: string;
    setActiveFilter: (filter: string) => void;
    purchaseOrders: PurchaseOrder[];
    setPurchaseOrders: React.Dispatch<React.SetStateAction<PurchaseOrder[]>>;
    tabCounts: { [key: string]: number };
    addLog: (action: string, details: string) => void;
    addNotification: (message: string, type?: 'info' | 'success' | 'warning' | 'error') => void;
    inventoryItems?: InventoryItem[];
    costPrices: CostPriceItem[];
    onSync: () => void;
    isSyncing: boolean;
}

const PoTable: React.FC<PoTableProps> = ({ activeFilter, setActiveFilter, purchaseOrders, setPurchaseOrders, tabCounts, addLog, addNotification, inventoryItems = [], costPrices = [], onSync, isSyncing }) => {
    const [filteredOrders, setFilteredOrders] = useState<PurchaseOrder[]>([]);
    const [openActionMenu, setOpenActionMenu] = useState<string | null>(null);
    const [expandedRowId, setExpandedRowId] = useState<string | null>(null);
    const [uploadModal, setUploadModal] = useState<{isOpen: boolean, po: PurchaseOrder | null, type: 'PO' | 'POD'}>({ isOpen: false, po: null, type: 'PO' });

    // Filtering State
    const [columnFilters, setColumnFilters] = useState<{ [key: string]: string }>({});
    const [activeFilterColumn, setActiveFilterColumn] = useState<string | null>(null);

    const menuRef = useRef<HTMLDivElement>(null);
    const filterMenuRef = useRef<HTMLDivElement>(null);

    const tabs = [
        { name: 'All POs' }, { name: 'New PO' }, { name: 'POC Verification'}, { name: 'Appointment to be taken' },
        { name: 'In-Transit' }, { name: 'GRN Pending' }, { name: 'GRN Updated' }, { name: 'RTO' }, { name: 'Closed' },
    ];

    const uniqueChannels = useMemo(() => Array.from(new Set(purchaseOrders.map(p => p.channel))), [purchaseOrders]);

    useEffect(() => {
        let orders = [...purchaseOrders];

        // 1. Tab-based filtering
        if (activeFilter !== 'All POs') {
             const filterMapping: { [key: string]: POStatus } = {
                'New PO': POStatus.NewPO, 'POC Verification': POStatus.POCPending, 'Appointment to be taken': POStatus.AppointmentPending,
                'In-Transit': POStatus.InTransit, 'GRN Pending': POStatus.GRNPending, 'GRN Updated': POStatus.GRNUpdated,
                'RTO': POStatus.RTO, 'Closed': POStatus.Closed,
            };
            const statusToFilter = filterMapping[activeFilter];
            if (statusToFilter) {
                orders = orders.filter(po => po.status === statusToFilter);
            }
        }

        // 2. Column-based filtering
        Object.keys(columnFilters).forEach((key) => {
            const filterValue = columnFilters[key].toLowerCase();
            if (filterValue) {
                orders = orders.filter(po => {
                    const itemValue = String((po as any)[key] || '').toLowerCase();
                    return itemValue.includes(filterValue);
                });
            }
        });

        setFilteredOrders(orders);
    }, [activeFilter, purchaseOrders, columnFilters]);

    // Handle click outside for action menu and filter menu
    useEffect(() => {
        const handleClickOutside = (event: MouseEvent) => {
            if (menuRef.current && !menuRef.current.contains(event.target as Node)) {
                setOpenActionMenu(null);
            }
            if (filterMenuRef.current && !filterMenuRef.current.contains(event.target as Node)) {
                setActiveFilterColumn(null);
            }
        };
        document.addEventListener('mousedown', handleClickOutside);
        return () => document.removeEventListener('mousedown', handleClickOutside);
    }, []);

    const toggleRowExpansion = (poId: string) => {
        setExpandedRowId(expandedRowId === poId ? null : poId);
    };

    const handleActionClick = (action: string, po: PurchaseOrder) => {
        if (action === 'Mark Delivered' && po.status === POStatus.InTransit) {
            setPurchaseOrders(prev => prev.map(o => o.id === po.id ? { ...o, status: POStatus.GRNPending, actionToBeTaken: 'Update GRN details' } : o));
            addLog('Status Change', `Marked PO ${po.poNumber} as Delivered`);
            addNotification(`PO ${po.poNumber} marked as Delivered`, 'success');
        } else {
            // Placeholder for other actions
            addLog('Action Request', `Requested ${action} for PO ${po.poNumber}`);
            addNotification(`Requested ${action} for PO ${po.poNumber}`, 'info');
        }
        setOpenActionMenu(null);
    };

    const poActions = [
        { name: 'Request Reattempt', icon: <RefreshIcon className="h-4 w-4 mr-3"/> },
        { name: 'Request RTO', icon: <ReplyIcon className="h-4 w-4 mr-3"/> },
        { name: 'Request Hold', icon: <PauseIcon className="h-4 w-4 mr-3"/> },
        { name: 'Mark Delivered', icon: <CheckCircleIcon className="h-4 w-4 mr-3"/> },
    ];

    const handleOpenUploadModal = (po: PurchaseOrder, type: 'PO' | 'POD') => setUploadModal({ isOpen: true, po, type });
    const handleCloseUploadModal = () => setUploadModal({ isOpen: false, po: null, type: 'PO' });
    const handleUploadSuccess = (updatedPo: PurchaseOrder) => {
        setPurchaseOrders(prev => prev.map(o => o.id === updatedPo.id ? updatedPo : o));
        addNotification(`Document uploaded successfully for PO ${updatedPo.poNumber}`, 'success');
    };

    const handleUpdateGrn = (poId: string) => {
        setPurchaseOrders(prev => prev.map(o => o.id === poId ? { ...o, status: POStatus.GRNUpdated, actionToBeTaken: 'Upload POD' } : o));
        addLog('Status Change', `Updated GRN details for PO ${poId}`); 
    };

    const renderActionToBeTaken = (po: PurchaseOrder) => {
        const action = po.actionToBeTaken;
        if (action === 'Upload PO PDF') {
            return <button onClick={() => handleOpenUploadModal(po, 'PO')} className="flex items-center gap-2 text-sm font-semibold text-blue-600 hover:text-blue-800"><PaperclipIcon className="h-4 w-4"/> {action}</button>;
        }
        if (action === 'Upload POD') {
            return <button onClick={() => handleOpenUploadModal(po, 'POD')} className="flex items-center gap-2 text-sm font-semibold text-blue-600 hover:text-blue-800"><PaperclipIcon className="h-4 w-4"/> {action}</button>;
        }
        if (action === 'Update GRN details') {
            return <button onClick={() => handleUpdateGrn(po.id)} className="flex items-center gap-2 text-sm font-semibold text-blue-600 hover:text-blue-800"><CheckCircleIcon className="h-4 w-4"/> {action}</button>;
        }
        return <span className="font-medium text-yellow-600">{action}</span>;
    };

    const renderSourceIcon = (source?: string) => {
        if (source === 'Email') {
            return <div className="p-1 bg-blue-100 rounded text-blue-600" title="Source: Email"><MailIcon className="h-3 w-3" /></div>
        }
        if (source === 'API') {
            return <div className="p-1 bg-purple-100 rounded text-purple-600" title="Source: API"><GlobeIcon className="h-3 w-3" /></div>
        }
        return null; // Manual or undefined
    };

    const updateColumnFilter = (key: string, value: string) => {
        setColumnFilters(prev => ({ ...prev, [key]: value }));
    };

    // Helper to check stock status based on fulfillable qty from sheet (FIFO)
    const getStockStatus = (po: PurchaseOrder) => {
        if (!po.items || po.items.length === 0) return 'unknown';

        let hasShortage = false;

        for (const item of po.items) {
             // If fulfillable qty (from FIFO sheet logic) is less than required qty, we have a shortage
             // Use item.fulfillableQty if present, otherwise default to 0 for check
             const fulfillable = item.fulfillableQty !== undefined ? item.fulfillableQty : 0;
             if (fulfillable < item.qty) {
                 hasShortage = true;
                 break;
             }
        }

        return hasShortage ? 'low' : 'ok';
    };

    const getCostPrice = (channel: string, articleCode: string): number | undefined => {
        const found = costPrices.find(cp => 
            cp.channel.toLowerCase().trim() === channel.toLowerCase().trim() && 
            cp.sku.toLowerCase().trim() === articleCode.toLowerCase().trim()
        );
        return found ? found.costPrice : undefined;
    };

    const hasCostMismatch = (po: PurchaseOrder): boolean => {
        if (!po.items) return false;
        return po.items.some(item => {
            const sheetCost = getCostPrice(po.channel, item.articleCode);
            // Check mismatch if sheet cost exists and differs from unit cost
            // Allow small float tolerance
            return sheetCost !== undefined && Math.abs((item.unitCost || 0) - sheetCost) > 0.05;
        });
    };

    return (
        <>
            {uploadModal.isOpen && uploadModal.po && (
                <FileUploadModal 
                    po={uploadModal.po}
                    uploadType={uploadModal.type}
                    onClose={handleCloseUploadModal}
                    onUploadSuccess={handleUploadSuccess}
                    addLog={addLog}
                />
            )}

            <div className="bg-white p-6 rounded-xl shadow-sm">
                 <div className="flex flex-col md:flex-row justify-between items-center gap-4 mb-6">
                    <div className="flex flex-wrap items-center gap-2">
                        {tabs.map(tab => {
                            const count = tabCounts[tab.name] || 0;
                            return (
                                <button key={tab.name} onClick={() => setActiveFilter(tab.name)}
                                    className={`px-3 py-1.5 text-sm font-semibold rounded-full border transition-colors flex items-center gap-2 ${
                                        activeFilter === tab.name 
                                            ? 'bg-partners-green text-white border-partners-green' 
                                            : 'bg-white text-gray-600 border-partners-border hover:bg-gray-50'
                                    }`}
                                >
                                    {tab.name}
                                    {count > 0 && (
                                        <span className={`text-xs font-bold rounded-full px-2 py-0.5 ${
                                            activeFilter === tab.name
                                                ? 'bg-white text-partners-green'
                                                : 'bg-gray-200 text-gray-700'
                                        }`}>
                                            {count}
                                        </span>
                                    )}
                                </button>
                            );
                        })}
                    </div>

                    <div className="flex items-center gap-3">
                         {Object.keys(columnFilters).length > 0 && (
                            <button 
                                onClick={() => setColumnFilters({})}
                                className="text-sm text-red-600 hover:text-red-800 font-medium flex items-center gap-1"
                            >
                                <XCircleIcon className="h-4 w-4"/> Clear Filters
                            </button>
                        )}
                        <button 
                            onClick={onSync}
                            disabled={isSyncing}
                            className={`flex items-center gap-2 px-3 py-2 text-sm font-medium text-white bg-blue-600 rounded-lg hover:bg-blue-700 transition-colors ${isSyncing ? 'opacity-70 cursor-wait' : ''}`}
                        >
                            <CloudDownloadIcon className={`h-4 w-4 ${isSyncing ? 'animate-bounce' : ''}`} /> 
                            {isSyncing ? 'Syncing...' : 'Sync Sources'}
                        </button>
                    </div>
                </div>

                <div className="mt-6 overflow-x-auto">
                    <table className="w-full text-sm text-left text-gray-600">
                        <thead className="text-xs text-gray-700 uppercase bg-gray-50">
                            <tr>
                                <th scope="col" className="p-4 w-4"></th> {/* Chevron column */}
                                <th scope="col" className="p-4"><input type="checkbox" className="h-4 w-4 rounded border-gray-300 text-green-600 focus:ring-green-500" /></th>

                                {/* PO Number Filter */}
                                <th scope="col" className="px-6 py-3 whitespace-nowrap relative group">
                                    <div className="flex items-center">
                                        PO number 
                                        <button 
                                            onClick={(e) => { e.stopPropagation(); setActiveFilterColumn(activeFilterColumn === 'poNumber' ? null : 'poNumber'); }}
                                            className={`ml-1 p-1 rounded hover:bg-gray-100 ${columnFilters['poNumber'] ? 'text-partners-green' : 'text-gray-400'}`}
                                        >
                                            <SearchIcon className="h-4 w-4"/>
                                        </button>
                                    </div>
                                    {activeFilterColumn === 'poNumber' && (
                                        <div ref={filterMenuRef} className="absolute top-full left-0 mt-2 w-48 bg-white rounded-lg shadow-xl border border-gray-100 z-20 p-3">
                                            <input
                                                type="text"
                                                placeholder="Search PO..."
                                                className="w-full px-3 py-2 text-sm border border-gray-200 rounded-md focus:outline-none focus:ring-2 focus:ring-partners-green/50 focus:border-partners-green"
                                                value={columnFilters['poNumber'] || ''}
                                                onChange={(e) => updateColumnFilter('poNumber', e.target.value)}
                                                autoFocus
                                            />
                                        </div>
                                    )}
                                </th>

                                {/* Status Filter */}
                                <th scope="col" className="px-6 py-3 whitespace-nowrap relative group">
                                    <div className="flex items-center">
                                        Status 
                                        <button 
                                            onClick={(e) => { e.stopPropagation(); setActiveFilterColumn(activeFilterColumn === 'status' ? null : 'status'); }}
                                            className={`ml-1 p-1 rounded hover:bg-gray-100 ${columnFilters['status'] ? 'text-partners-green' : 'text-gray-400'}`}
                                        >
                                            <FilterIcon className="h-4 w-4"/>
                                        </button>
                                    </div>
                                    {activeFilterColumn === 'status' && (
                                        <div ref={filterMenuRef} className="absolute top-full left-0 mt-2 w-48 bg-white rounded-lg shadow-xl border border-gray-100 z-20 p-3">
                                            <select
                                                className="w-full px-3 py-2 text-sm border border-gray-200 rounded-md focus:outline-none focus:ring-2 focus:ring-partners-green/50 focus:border-partners-green"
                                                value={columnFilters['status'] || ''}
                                                onChange={(e) => updateColumnFilter('status', e.target.value)}
                                            >
                                                <option value="">All Statuses</option>
                                                {Object.values(POStatus).map(status => (
                                                    <option key={status} value={status}>{status}</option>
                                                ))}
                                            </select>
                                        </div>
                                    )}
                                </th>

                                {/* Channel Filter */}
                                <th scope="col" className="px-6 py-3 whitespace-nowrap relative group">
                                    <div className="flex items-center">
                                        Channel 
                                        <button 
                                            onClick={(e) => { e.stopPropagation(); setActiveFilterColumn(activeFilterColumn === 'channel' ? null : 'channel'); }}
                                            className={`ml-1 p-1 rounded hover:bg-gray-100 ${columnFilters['channel'] ? 'text-partners-green' : 'text-gray-400'}`}
                                        >
                                            <FilterIcon className="h-4 w-4"/>
                                        </button>
                                    </div>
                                    {activeFilterColumn === 'channel' && (
                                        <div ref={filterMenuRef} className="absolute top-full left-0 mt-2 w-48 bg-white rounded-lg shadow-xl border border-gray-100 z-20 p-3">
                                            <select
                                                className="w-full px-3 py-2 text-sm border border-gray-200 rounded-md focus:outline-none focus:ring-2 focus:ring-partners-green/50 focus:border-partners-green"
                                                value={columnFilters['channel'] || ''}
                                                onChange={(e) => updateColumnFilter('channel', e.target.value)}
                                            >
                                                <option value="">All Channels</option>
                                                {uniqueChannels.map(ch => (
                                                    <option key={ch} value={ch}>{ch}</option>
                                                ))}
                                            </select>
                                        </div>
                                    )}
                                </th>

                                {/* Store Code Filter */}
                                <th scope="col" className="px-6 py-3 whitespace-nowrap relative group">
                                    <div className="flex items-center">
                                        Store Code 
                                        <button 
                                            onClick={(e) => { e.stopPropagation(); setActiveFilterColumn(activeFilterColumn === 'storeCode' ? null : 'storeCode'); }}
                                            className={`ml-1 p-1 rounded hover:bg-gray-100 ${columnFilters['storeCode'] ? 'text-partners-green' : 'text-gray-400'}`}
                                        >
                                            <SearchIcon className="h-4 w-4"/>
                                        </button>
                                    </div>
                                    {activeFilterColumn === 'storeCode' && (
                                        <div ref={filterMenuRef} className="absolute top-full left-0 mt-2 w-48 bg-white rounded-lg shadow-xl border border-gray-100 z-20 p-3">
                                            <input
                                                type="text"
                                                placeholder="Search Store Code..."
                                                className="w-full px-3 py-2 text-sm border border-gray-200 rounded-md focus:outline-none focus:ring-2 focus:ring-partners-green/50 focus:border-partners-green"
                                                value={columnFilters['storeCode'] || ''}
                                                onChange={(e) => updateColumnFilter('storeCode', e.target.value)}
                                                autoFocus
                                            />
                                        </div>
                                    )}
                                </th>

                                <th scope="col" className="px-6 py-3 whitespace-nowrap">Qty / Amount <SortIcon className="inline-block ml-1 text-gray-400"/></th>
                                <th scope="col" className="px-6 py-3 whitespace-nowrap">Order Date <SortIcon className="inline-block ml-1 text-gray-400"/></th>
                                <th scope="col" className="px-6 py-3 whitespace-nowrap">Stock Status</th>
                                <th scope="col" className="px-6 py-3 whitespace-nowrap">Action to be Taken</th>
                                <th scope="col" className="px-6 py-3">Actions</th>
                            </tr>
                        </thead>
                        <tbody>
                            {filteredOrders.length === 0 ? (
                                <tr>
                                    <td colSpan={11} className="px-6 py-8 text-center text-gray-500">
                                        No purchase orders found matching your filters.
                                    </td>
                                </tr>
                            ) : (
                                filteredOrders.map((po) => {
                                    const stockStatus = getStockStatus(po);
                                    const isExpanded = expandedRowId === po.id;
                                    const hasCostError = hasCostMismatch(po);

                                    return (
                                    <Fragment key={po.id}>
                                        <tr className={`border-b hover:bg-gray-50 transition-colors ${isExpanded ? 'bg-gray-50' : 'bg-white'}`}>
                                            <td className="p-4 text-center">
                                                <button 
                                                    onClick={() => toggleRowExpansion(po.id)}
                                                    className="text-gray-400 hover:text-partners-green focus:outline-none"
                                                >
                                                    {isExpanded ? <ChevronDownIcon /> : <ChevronRightIcon />}
                                                </button>
                                            </td>
                                            <td className="p-4"><input type="checkbox" className="h-4 w-4 rounded border-gray-300 text-green-600 focus:ring-green-500" /></td>
                                            <td 
                                                className="px-6 py-4 font-medium text-partners-green whitespace-nowrap cursor-pointer hover:underline flex items-center gap-2"
                                                onClick={() => toggleRowExpansion(po.id)}
                                            >
                                                {po.poNumber}
                                                {renderSourceIcon(po.source)}
                                                {hasCostError && (
                                                    <span title="Cost Price Mismatch">
                                                        <XCircleIcon className="h-4 w-4 text-red-500" />
                                                    </span>
                                                )}
                                            </td>
                                            <td className="px-6 py-4"><StatusBadge status={po.status} /></td>
                                            <td className="px-6 py-4 whitespace-nowrap">{po.channel}</td>
                                            <td className="px-6 py-4 whitespace-nowrap">{po.storeCode}</td>
                                            <td className="px-6 py-4 whitespace-nowrap">{po.qty} / ₹{po.amount.toLocaleString('en-IN')}</td>
                                            <td className="px-6 py-4 whitespace-nowrap">{po.orderDate}</td>
                                            <td className="px-6 py-4 whitespace-nowrap">
                                                {stockStatus === 'ok' && (
                                                    <span className="flex items-center text-green-600 text-xs font-semibold bg-green-50 px-2 py-1 rounded-full w-fit">
                                                        <CheckCircleIcon className="h-3 w-3 mr-1"/> Fulfillable
                                                    </span>
                                                )}
                                                {stockStatus === 'low' && (
                                                    <span className="flex items-center text-red-600 text-xs font-semibold bg-red-50 px-2 py-1 rounded-full w-fit">
                                                        <XCircleIcon className="h-3 w-3 mr-1"/> Shortage
                                                    </span>
                                                )}
                                                {stockStatus === 'unknown' && <span className="text-gray-400 text-xs">-</span>}
                                            </td>
                                            <td className="px-6 py-4 whitespace-nowrap">{renderActionToBeTaken(po)}</td>
                                            <td className="px-6 py-4 relative">
                                                <button 
                                                    onClick={() => !hasCostError && setOpenActionMenu(openActionMenu === po.id ? null : po.id)} 
                                                    className={`${hasCostError ? 'text-gray-300 cursor-not-allowed' : 'text-gray-500 hover:text-partners-green'}`}
                                                    title={hasCostError ? 'Action disabled: Cost Price Mismatch' : 'Actions'}
                                                >
                                                    {hasCostError ? <LockClosedIcon className="h-5 w-5" /> : <DotsVerticalIcon />}
                                                </button>
                                                {openActionMenu === po.id && !hasCostError && (
                                                    <div ref={menuRef} className="absolute right-0 mt-2 w-48 bg-white rounded-md shadow-lg z-10 border border-partners-border">
                                                        <div className="py-1">
                                                            {poActions.map(action => (
                                                                <button 
                                                                key={action.name} 
                                                                onClick={() => handleActionClick(action.name, po)}
                                                                className="w-full text-left flex items-center px-4 py-2 text-sm text-gray-700 hover:bg-gray-100 disabled:text-gray-400 disabled:bg-white"
                                                                disabled={action.name === 'Mark Delivered' && po.status !== POStatus.InTransit}
                                                                >
                                                                    {action.icon} {action.name}
                                                                </button>
                                                            ))}
                                                        </div>
                                                    </div>
                                                )}
                                            </td>
                                        </tr>

                                        {/* Expanded Details Row */}
                                        {isExpanded && (
                                            <tr className="bg-gray-50">
                                                <td colSpan={11} className="px-4 py-4 sm:px-12 sm:py-6">
                                                    <div className="bg-white border border-gray-200 rounded-lg p-4 shadow-sm">
                                                        <div className="flex items-center justify-between mb-4">
                                                            <h4 className="text-sm font-bold text-gray-800 flex items-center gap-2">
                                                                <CubeIcon className="h-4 w-4 text-partners-green" /> 
                                                                Fulfillment & Cost Details
                                                            </h4>
                                                            {po.carrier && (
                                                                <span className="text-xs text-gray-500 bg-gray-100 px-2 py-1 rounded">
                                                                    Carrier: {po.carrier} | AWB: {po.awb || 'N/A'}
                                                                </span>
                                                            )}
                                                        </div>

                                                        {!po.items || po.items.length === 0 ? (
                                                            <p className="text-sm text-gray-500 italic">No line item details available for this PO.</p>
                                                        ) : (
                                                            <table className="w-full text-xs text-left">
                                                                <thead>
                                                                    <tr className="text-gray-500 border-b border-gray-100">
                                                                        <th className="py-2">EasyEcom Main SKU</th>
                                                                        <th className="py-2">Item Name</th>
                                                                        <th className="py-2 text-right">MRP</th>
                                                                        <th className="py-2 text-right">Unit Cost (PO)</th>
                                                                        <th className="py-2 text-right">Sheet Cost</th>
                                                                        <th className="py-2 text-right">Required Qty</th>
                                                                        <th className="py-2 text-right">Fulfillable Qty (FIFO)</th>
                                                                        <th className="py-2 text-center">Status</th>
                                                                    </tr>
                                                                </thead>
                                                                <tbody>
                                                                    {po.items.map((item, idx) => {
                                                                        const invItem = inventoryItems.find(i => i.articleCode === item.articleCode && i.channel === po.channel) 
                                                                                       || inventoryItems.find(i => i.articleCode === item.articleCode);

                                                                        // Use fulfillableQty directly from PO Item (calculated via FIFO in Sheet)
                                                                        const fulfillable = item.fulfillableQty !== undefined ? item.fulfillableQty : 0;
                                                                        const isShortage = fulfillable < item.qty;

                                                                        // Cost Check
                                                                        const sheetCost = getCostPrice(po.channel, item.articleCode);
                                                                        const isCostMismatch = sheetCost !== undefined && Math.abs((item.unitCost || 0) - sheetCost) > 0.05;

                                                                        return (
                                                                            <tr key={idx} className={`border-b border-gray-50 ${isShortage || isCostMismatch ? 'bg-red-50' : ''}`}>
                                                                                <td className="py-2 font-medium text-gray-800">{item.masterSku || (invItem ? invItem.sku : '-')}</td>
                                                                                <td className="py-2 text-gray-600 truncate max-w-xs">{item.itemName || (invItem ? invItem.itemName : 'Item not found')}</td>
                                                                                <td className="py-2 text-right text-gray-600">₹{item.mrp?.toLocaleString('en-IN') || 0}</td>
                                                                                <td className={`py-2 text-right ${isCostMismatch ? 'text-red-600 font-bold' : 'text-gray-600'}`}>
                                                                                    ₹{item.unitCost?.toLocaleString('en-IN') || 0}
                                                                                </td>
                                                                                <td className="py-2 text-right text-gray-600">
                                                                                    {sheetCost !== undefined ? `₹${sheetCost.toLocaleString('en-IN')}` : '-'}
                                                                                </td>
                                                                                <td className="py-2 text-right font-medium text-gray-900">{item.qty}</td>
                                                                                <td className={`py-2 text-right font-bold ${isShortage ? 'text-red-600' : 'text-green-600'}`}>
                                                                                    {fulfillable}
                                                                                </td>
                                                                                <td className="py-2 text-center">
                                                                                    {isCostMismatch ? (
                                                                                        <span className="text-red-600 font-bold" title="Price Mismatch">Price Err</span>
                                                                                    ) : isShortage ? (
                                                                                        <span className="text-red-600 font-bold">Short</span>
                                                                                    ) : (
                                                                                        <span className="text-green-600">OK</span>
                                                                                    )}
                                                                                </td>
                                                                            </tr>
                                                                        );
                                                                    })}
                                                                </tbody>
                                                            </table>
                                                        )}
                                                        {hasCostError && (
                                                            <div className="mt-3 bg-red-100 text-red-700 p-2 rounded text-xs font-semibold text-center">
                                                                Action Blocked: One or more items have a cost price mismatch with the master sheet.
                                                            </div>
                                                        )}
                                                    </div>
                                                </td>
                                            </tr>
                                        )}
                                    </Fragment>
                                    );
                                })
                            )}
                        </tbody>
                    </table>
                </div>
            </div>
        </>
    );
};

