export const fetchInventoryFromSheet = async (): Promise<InventoryItem[]> => {
    try {
        const response = await fetch(`${API_URL}?action=getInventory`, {
            method: 'GET',
            redirect: 'follow',
            mode: 'cors',
            credentials: 'omit' // Critical for GAS web apps to avoid auth conflicts
        });

        if (!response.ok) {
            throw new Error(`HTTP Error: ${response.status}`);
        }

        const json = await response.json();
        if (json.status === 'success') {
            return transformSheetDataToInventory(json.data);
        } else {
            console.error("API Error (Inventory):", json.message);
            // Return empty array instead of throwing to prevent app crash if sheet is missing
            return [];
        }
    } catch (error) {
        console.error("Failed to fetch inventory:", error);
        return [];
    }
};

export const fetchPurchaseOrders = async (): Promise<PurchaseOrder[]> => {
