import React, { useState, useEffect, useRef, useMemo, Fragment } from 'react';
import { POStatus, type PurchaseOrder, type InventoryItem, POItem } from '../types';
import StatusBadge from './StatusBadge';
import { DotsVerticalIcon, FilterIcon, SearchIcon, SortIcon, RefreshIcon, ReplyIcon, PauseIcon, CheckCircleIcon, UploadIcon, PaperclipIcon, XCircleIcon, CloudDownloadIcon, CogIcon, GlobeIcon, MailIcon, ChevronDownIcon, ChevronRightIcon, CubeIcon, LockClosedIcon } from './icons/Icons';

interface FileUploadModalProps {
    po: PurchaseOrder;
    uploadType: 'PO' | 'POD';
    onClose: () => void;
    onUploadSuccess: (updatedPo: PurchaseOrder) => void;
    addLog: (action: string, details: string) => void;
}

const FileUploadModal: React.FC<FileUploadModalProps> = ({ po, uploadType, onClose, onUploadSuccess, addLog }) => {
    const [file, setFile] = useState<File | null>(null);
    const [error, setError] = useState<string | null>(null);
    const [isUploading, setIsUploading] = useState(false);

    const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        if (e.target.files && e.target.files[0]) {
            setFile(e.target.files[0]);
            setError(null);
        }
    };

    const validateFile = () => {
        if (!file) {
            setError('Please select a file to upload.');
            return false;
        }

        const allowedFormats = uploadType === 'PO' 
            ? ['.pdf'] 
            : ['.jpg', '.jpeg', '.png', '.webp'];
        const fileExtension = '.' + file.name.split('.').pop()?.toLowerCase();

        if (!allowedFormats.includes(fileExtension)) {
            setError(`Invalid file format. Please upload one of: ${allowedFormats.join(', ')}`);
            return false;
        }

        const fileNameWithoutExt = file.name.replace(/\.[^/.]+$/, "");
        const targetId = uploadType === 'PO' ? po.poNumber : po.awb;

        if (fileNameWithoutExt !== targetId) {
            setError(`Filename must match the ${uploadType === 'PO' ? 'PO Number' : 'AWB'} (${targetId}).`);
            return false;
        }

        return true;
    };

    const handleUpload = () => {
        if (!validateFile()) return;

        setIsUploading(true);
        // Simulate API call
        setTimeout(() => {
            const updatedPo = {
                ...po,
                ...(uploadType === 'PO' && { poPdfUrl: `path/to/${file?.name}`, actionToBeTaken: 'Verify POC', status: POStatus.POCPending }),
                ...(uploadType === 'POD' && { podImageUrl: `path/to/${file?.name}`, actionToBeTaken: undefined, status: POStatus.Closed }),
            };
            onUploadSuccess(updatedPo);
            addLog('Upload', `Uploaded ${uploadType} document for PO ${po.poNumber}`);
            setIsUploading(false);
            onClose();
        }, 1500);
    };

    return (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50 p-4">
            <div className="bg-white rounded-lg shadow-xl w-full max-w-md">
                <div className="p-6 border-b">
                    <h3 className="text-lg font-semibold text-gray-800">Upload {uploadType} Document</h3>
                    <p className="text-sm text-gray-500 mt-1">For PO Number: <span className="font-bold text-partners-green">{po.poNumber}</span></p>
                </div>
                <div className="p-6">
                    <div className="border-2 border-dashed border-gray-300 rounded-lg p-8 text-center bg-gray-50 hover:border-partners-green transition">
                        <UploadIcon className="mx-auto h-12 w-12 text-gray-400" />
                        <label htmlFor="file-upload" className="mt-4 text-sm font-semibold text-partners-green cursor-pointer">
                            {file ? 'Change file' : 'Select a file'}
                        </label>
                        <input id="file-upload" name="file-upload" type="file" className="sr-only" onChange={handleFileChange} />
                        <p className="mt-1 text-xs text-gray-500">{file ? `Selected: ${file.name}` : 'Drag and drop or click to select.'}</p>
                    </div>
                    {error && (
                         <div className="mt-3 flex items-center text-sm text-red-600">
                            <XCircleIcon className="h-4 w-4 mr-2" />
                            {error}
                        </div>
                    )}
                </div>
                <div className="px-6 py-4 bg-gray-50 flex justify-end gap-3 rounded-b-lg">
                    <button onClick={onClose} className="px-4 py-2 text-sm font-medium text-gray-700 bg-white border border-gray-300 rounded-md hover:bg-gray-50">Cancel</button>
                    <button onClick={handleUpload} disabled={isUploading || !file} className="px-4 py-2 text-sm font-medium text-white bg-partners-green border border-transparent rounded-md hover:bg-green-700 disabled:bg-gray-400 disabled:cursor-not-allowed flex items-center">
                        {isUploading ? 'Uploading...' : 'Upload File'}
                    </button>
                </div>
            </div>
        </div>
    );
};

interface PoTableProps {
    activeFilter: string;
    setActiveFilter: (filter: string) => void;
    purchaseOrders: PurchaseOrder[];
    setPurchaseOrders: React.Dispatch<React.SetStateAction<PurchaseOrder[]>>;
    tabCounts: { [key: string]: number };
    addLog: (action: string, details: string) => void;
    addNotification: (message: string, type?: 'info' | 'success' | 'warning' | 'error') => void;
    inventoryItems?: InventoryItem[];
    onSync: () => void;
    isSyncing: boolean;
}

const PoTable: React.FC<PoTableProps> = ({ activeFilter, setActiveFilter, purchaseOrders, setPurchaseOrders, tabCounts, addLog, addNotification, inventoryItems = [], onSync, isSyncing }) => {
    const [filteredOrders, setFilteredOrders] = useState<PurchaseOrder[]>([]);
    const [openActionMenu, setOpenActionMenu] = useState<string | null>(null);
    const [expandedRowId, setExpandedRowId] = useState<string | null>(null);
    const [uploadModal, setUploadModal] = useState<{isOpen: boolean, po: PurchaseOrder | null, type: 'PO' | 'POD'}>({ isOpen: false, po: null, type: 'PO' });

    // Filtering State
    const [columnFilters, setColumnFilters] = useState<{ [key: string]: string }>({});
    const [activeFilterColumn, setActiveFilterColumn] = useState<string | null>(null);

    const menuRef = useRef<HTMLDivElement>(null);
    const filterMenuRef = useRef<HTMLDivElement>(null);

    const tabs = [
        { name: 'All POs' }, { name: 'New PO' }, { name: 'POC Verification'}, { name: 'Appointment to be taken' },
        { name: 'In-Transit' }, { name: 'GRN Pending' }, { name: 'GRN Updated' }, { name: 'RTO' }, { name: 'Closed' },
    ];

    const uniqueChannels = useMemo(() => Array.from(new Set(purchaseOrders.map(p => p.channel))), [purchaseOrders]);

    useEffect(() => {
        let orders = [...purchaseOrders];

        // 1. Tab-based filtering
        if (activeFilter !== 'All POs') {
             const filterMapping: { [key: string]: POStatus } = {
                'New PO': POStatus.NewPO, 'POC Verification': POStatus.POCPending, 'Appointment to be taken': POStatus.AppointmentPending,
                'In-Transit': POStatus.InTransit, 'GRN Pending': POStatus.GRNPending, 'GRN Updated': POStatus.GRNUpdated,
                'RTO': POStatus.RTO, 'Closed': POStatus.Closed,
            };
            const statusToFilter = filterMapping[activeFilter];
            if (statusToFilter) {
                orders = orders.filter(po => po.status === statusToFilter);
            }
        }

        // 2. Column-based filtering
        Object.keys(columnFilters).forEach((key) => {
            const filterValue = columnFilters[key].toLowerCase();
            if (filterValue) {
                orders = orders.filter(po => {
                    const itemValue = String((po as any)[key] || '').toLowerCase();
                    return itemValue.includes(filterValue);
                });
            }
        });

        setFilteredOrders(orders);
    }, [activeFilter, purchaseOrders, columnFilters]);

    // Handle click outside for action menu and filter menu
    useEffect(() => {
        const handleClickOutside = (event: MouseEvent) => {
            if (menuRef.current && !menuRef.current.contains(event.target as Node)) {
                setOpenActionMenu(null);
            }
            if (filterMenuRef.current && !filterMenuRef.current.contains(event.target as Node)) {
                setActiveFilterColumn(null);
            }
        };
        document.addEventListener('mousedown', handleClickOutside);
        return () => document.removeEventListener('mousedown', handleClickOutside);
    }, []);

    const toggleRowExpansion = (poId: string) => {
        setExpandedRowId(expandedRowId === poId ? null : poId);
    };

    const handleActionClick = (action: string, po: PurchaseOrder) => {
        if (action === 'Mark Delivered' && po.status === POStatus.InTransit) {
            setPurchaseOrders(prev => prev.map(o => o.id === po.id ? { ...o, status: POStatus.GRNPending, actionToBeTaken: 'Update GRN details' } : o));
            addLog('Status Change', `Marked PO ${po.poNumber} as Delivered`);
            addNotification(`PO ${po.poNumber} marked as Delivered`, 'success');
        } else {
            // Placeholder for other actions
            addLog('Action Request', `Requested ${action} for PO ${po.poNumber}`);
            addNotification(`Requested ${action} for PO ${po.poNumber}`, 'info');
        }
        setOpenActionMenu(null);
    };

    const poActions = [
        { name: 'Request Reattempt', icon: <RefreshIcon className="h-4 w-4 mr-3"/> },
        { name: 'Request RTO', icon: <ReplyIcon className="h-4 w-4 mr-3"/> },
        { name: 'Request Hold', icon: <PauseIcon className="h-4 w-4 mr-3"/> },
        { name: 'Mark Delivered', icon: <CheckCircleIcon className="h-4 w-4 mr-3"/> },
    ];

    const handleOpenUploadModal = (po: PurchaseOrder, type: 'PO' | 'POD') => setUploadModal({ isOpen: true, po, type });
    const handleCloseUploadModal = () => setUploadModal({ isOpen: false, po: null, type: 'PO' });
    const handleUploadSuccess = (updatedPo: PurchaseOrder) => {
        setPurchaseOrders(prev => prev.map(o => o.id === updatedPo.id ? updatedPo : o));
        addNotification(`Document uploaded successfully for PO ${updatedPo.poNumber}`, 'success');
    };

    const handleUpdateGrn = (poId: string) => {
        setPurchaseOrders(prev => prev.map(o => o.id === poId ? { ...o, status: POStatus.GRNUpdated, actionToBeTaken: 'Upload POD' } : o));
        addLog('Status Change', `Updated GRN details for PO ${poId}`); 
    };

    const renderActionToBeTaken = (po: PurchaseOrder) => {
        const action = po.actionToBeTaken;
        if (action === 'Upload PO PDF') {
            return <button onClick={() => handleOpenUploadModal(po, 'PO')} className="flex items-center gap-2 text-sm font-semibold text-blue-600 hover:text-blue-800"><PaperclipIcon className="h-4 w-4"/> {action}</button>;
        }
        if (action === 'Upload POD') {
            return <button onClick={() => handleOpenUploadModal(po, 'POD')} className="flex items-center gap-2 text-sm font-semibold text-blue-600 hover:text-blue-800"><PaperclipIcon className="h-4 w-4"/> {action}</button>;
        }
        if (action === 'Update GRN details') {
            return <button onClick={() => handleUpdateGrn(po.id)} className="flex items-center gap-2 text-sm font-semibold text-blue-600 hover:text-blue-800"><CheckCircleIcon className="h-4 w-4"/> {action}</button>;
        }
        return <span className="font-medium text-yellow-600">{action}</span>;
    };

    const renderSourceIcon = (source?: string) => {
        if (source === 'Email') {
            return <div className="p-1 bg-blue-100 rounded text-blue-600" title="Source: Email"><MailIcon className="h-3 w-3" /></div>
        }
        if (source === 'API') {
            return <div className="p-1 bg-purple-100 rounded text-purple-600" title="Source: API"><GlobeIcon className="h-3 w-3" /></div>
        }
        return null; // Manual or undefined
    };

    const updateColumnFilter = (key: string, value: string) => {
        setColumnFilters(prev => ({ ...prev, [key]: value }));
    };

    // Helper to check stock status based on fulfillable qty from sheet (FIFO)
    const getStockStatus = (po: PurchaseOrder) => {
        if (!po.items || po.items.length === 0) return 'unknown';

        let hasShortage = false;

        for (const item of po.items) {
             // If fulfillable qty (from FIFO sheet logic) is less than required qty, we have a shortage
             // Use item.fulfillableQty if present, otherwise default to 0 for check
             const fulfillable = item.fulfillableQty !== undefined ? item.fulfillableQty : 0;
             if (fulfillable < item.qty) {
                 hasShortage = true;
                 break;
             }
        }

        return hasShortage ? 'low' : 'ok';
    };

    const hasCostMismatch = (po: PurchaseOrder): boolean => {
        if (!po.items) return false;
        return po.items.some(item => {
            const status = item.priceCheckStatus?.toLowerCase() || '';
            // If status exists and is not OK or Match, it's a mismatch
            return status !== '' && status !== 'ok' && status !== 'match';
        });
    };

    return (
        <>
            {uploadModal.isOpen && uploadModal.po && (
                <FileUploadModal 
                    po={uploadModal.po}
                    uploadType={uploadModal.type}
                    onClose={handleCloseUploadModal}
                    onUploadSuccess={handleUploadSuccess}
                    addLog={addLog}
                />
            )}

            <div className="bg-white p-6 rounded-xl shadow-sm">
                 <div className="flex flex-col md:flex-row justify-between items-center gap-4 mb-6">
                    <div className="flex flex-wrap items-center gap-2">
                        {tabs.map(tab => {
                            const count = tabCounts[tab.name] || 0;
                            return (
                                <button key={tab.name} onClick={() => setActiveFilter(tab.name)}
                                    className={`px-3 py-1.5 text-sm font-semibold rounded-full border transition-colors flex items-center gap-2 ${
                                        activeFilter === tab.name 
                                            ? 'bg-partners-green text-white border-partners-green' 
                                            : 'bg-white text-gray-600 border-partners-border hover:bg-gray-50'
                                    }`}
                                >
                                    {tab.name}
                                    {count > 0 && (
                                        <span className={`text-xs font-bold rounded-full px-2 py-0.5 ${
                                            activeFilter === tab.name
                                                ? 'bg-white text-partners-green'
                                                : 'bg-gray-200 text-gray-700'
                                        }`}>
                                            {count}
                                        </span>
                                    )}
                                </button>
                            );
                        })}
                    </div>

                    <div className="flex items-center gap-3">
                         {Object.keys(columnFilters).length > 0 && (
                            <button 
                                onClick={() => setColumnFilters({})}
                                className="text-sm text-red-600 hover:text-red-800 font-medium flex items-center gap-1"
                            >
                                <XCircleIcon className="h-4 w-4"/> Clear Filters
                            </button>
                        )}
                        <button 
                            onClick={onSync}
                            disabled={isSyncing}
                            className={`flex items-center gap-2 px-3 py-2 text-sm font-medium text-white bg-blue-600 rounded-lg hover:bg-blue-700 transition-colors ${isSyncing ? 'opacity-70 cursor-wait' : ''}`}
                        >
                            <CloudDownloadIcon className={`h-4 w-4 ${isSyncing ? 'animate-bounce' : ''}`} /> 
                            {isSyncing ? 'Syncing...' : 'Sync Sources'}
                        </button>
                    </div>
                </div>

                <div className="mt-6 overflow-x-auto">
                    <table className="w-full text-sm text-left text-gray-600">
                        <thead className="text-xs text-gray-700 uppercase bg-gray-50">
