                                    </div>
                                    {activeFilterColumn === 'storeCode' && (
                                        <div ref={filterMenuRef} className="absolute top-full left-0 mt-2 w-48 bg-white rounded-lg shadow-xl border border-gray-100 z-20 p-3">
                                            <input
                                                type="text"
                                                placeholder="Search Store Code..."
                                                className="w-full px-3 py-2 text-sm border border-gray-200 rounded-md focus:outline-none focus:ring-2 focus:ring-partners-green/50 focus:border-partners-green"
                                                value={columnFilters['storeCode'] || ''}
                                                onChange={(e) => updateColumnFilter('storeCode', e.target.value)}
                                                autoFocus
                                            />
                                        </div>
                                    )}
                                </th>

                                <th scope="col" className="px-6 py-3 whitespace-nowrap">Qty / Amount <SortIcon className="inline-block ml-1 text-gray-400"/></th>
                                <th scope="col" className="px-6 py-3 whitespace-nowrap">Order Date <SortIcon className="inline-block ml-1 text-gray-400"/></th>
                                <th scope="col" className="px-6 py-3 whitespace-nowrap">Stock Status</th>
                                <th scope="col" className="px-6 py-3 whitespace-nowrap">Action to be Taken</th>
                                <th scope="col" className="px-6 py-3">Actions</th>
                            </tr>
                        </thead>
                        <tbody>
                            {filteredOrders.length === 0 ? (
                                <tr>
                                    <td colSpan={11} className="px-6 py-8 text-center text-gray-500">
                                        No purchase orders found matching your filters.
                                    </td>
                                </tr>
                            ) : (
                                filteredOrders.map((po) => {
                                    const stockStatus = getStockStatus(po);
                                    const isExpanded = expandedRowId === po.id;
                                    const hasCostError = hasCostMismatch(po);

                                    return (
                                    <Fragment key={po.id}>
                                        <tr className={`border-b hover:bg-gray-50 transition-colors ${isExpanded ? 'bg-gray-50' : 'bg-white'}`}>
                                            <td className="p-4 text-center">
                                                <button 
                                                    onClick={() => toggleRowExpansion(po.id)}
                                                    className="text-gray-400 hover:text-partners-green focus:outline-none"
                                                >
                                                    {isExpanded ? <ChevronDownIcon /> : <ChevronRightIcon />}
                                                </button>
                                            </td>
                                            <td className="p-4"><input type="checkbox" className="h-4 w-4 rounded border-gray-300 text-green-600 focus:ring-green-500" /></td>
                                            <td 
                                                className="px-6 py-4 font-medium text-partners-green whitespace-nowrap cursor-pointer hover:underline flex items-center gap-2"
                                                onClick={() => toggleRowExpansion(po.id)}
                                            >
                                                {po.poNumber}
                                                {renderSourceIcon(po.source)}
                                                {hasCostError && (
                                                    <span title="Price Check Mismatch">
                                                        <XCircleIcon className="h-4 w-4 text-red-500" />
                                                    </span>
                                                )}
                                            </td>
                                            <td className="px-6 py-4"><StatusBadge status={po.status} /></td>
                                            <td className="px-6 py-4 whitespace-nowrap">{po.channel}</td>
                                            <td className="px-6 py-4 whitespace-nowrap">{po.storeCode}</td>
                                            <td className="px-6 py-4 whitespace-nowrap">{po.qty} / ₹{po.amount.toLocaleString('en-IN')}</td>
                                            <td className="px-6 py-4 whitespace-nowrap">{po.orderDate}</td>
                                            <td className="px-6 py-4 whitespace-nowrap">
                                                {stockStatus === 'ok' && (
                                                    <span className="flex items-center text-green-600 text-xs font-semibold bg-green-50 px-2 py-1 rounded-full w-fit">
                                                        <CheckCircleIcon className="h-3 w-3 mr-1"/> Fulfillable
                                                    </span>
                                                )}
                                                {stockStatus === 'low' && (
                                                    <span className="flex items-center text-red-600 text-xs font-semibold bg-red-50 px-2 py-1 rounded-full w-fit">
                                                        <XCircleIcon className="h-3 w-3 mr-1"/> Shortage
                                                    </span>
                                                )}
                                                {stockStatus === 'unknown' && <span className="text-gray-400 text-xs">-</span>}
                                            </td>
                                            <td className="px-6 py-4 whitespace-nowrap">{renderActionToBeTaken(po)}</td>
                                            <td className="px-6 py-4 relative">
                                                <button 
                                                    onClick={() => !hasCostError && setOpenActionMenu(openActionMenu === po.id ? null : po.id)} 
                                                    className={`${hasCostError ? 'text-gray-300 cursor-not-allowed' : 'text-gray-500 hover:text-partners-green'}`}
                                                    title={hasCostError ? 'Action disabled: Cost Price Mismatch' : 'Actions'}
                                                >
                                                    {hasCostError ? <LockClosedIcon className="h-5 w-5" /> : <DotsVerticalIcon />}
                                                </button>
                                                {openActionMenu === po.id && !hasCostError && (
                                                    <div ref={menuRef} className="absolute right-0 mt-2 w-48 bg-white rounded-md shadow-lg z-10 border border-partners-border">
                                                        <div className="py-1">
                                                            {poActions.map(action => (
                                                                <button 
                                                                key={action.name} 
                                                                onClick={() => handleActionClick(action.name, po)}
                                                                className="w-full text-left flex items-center px-4 py-2 text-sm text-gray-700 hover:bg-gray-100 disabled:text-gray-400 disabled:bg-white"
                                                                disabled={action.name === 'Mark Delivered' && po.status !== POStatus.InTransit}
                                                                >
                                                                    {action.icon} {action.name}
                                                                </button>
                                                            ))}
                                                        </div>
                                                    </div>
                                                )}
                                            </td>
                                        </tr>

                                        {/* Expanded Details Row */}
                                        {isExpanded && (
                                            <tr className="bg-gray-50">
                                                <td colSpan={11} className="px-4 py-4 sm:px-12 sm:py-6">
                                                    <div className="bg-white border border-gray-200 rounded-lg p-4 shadow-sm">
                                                        <div className="flex items-center justify-between mb-4">
                                                            <h4 className="text-sm font-bold text-gray-800 flex items-center gap-2">
                                                                <CubeIcon className="h-4 w-4 text-partners-green" /> 
                                                                Fulfillment & Cost Details
                                                            </h4>
                                                            {po.carrier && (
                                                                <span className="text-xs text-gray-500 bg-gray-100 px-2 py-1 rounded">
                                                                    Carrier: {po.carrier} | AWB: {po.awb || 'N/A'}
                                                                </span>
                                                            )}
                                                        </div>

                                                        {!po.items || po.items.length === 0 ? (
                                                            <p className="text-sm text-gray-500 italic">No line item details available for this PO.</p>
                                                        ) : (
                                                            <table className="w-full text-xs text-left">
                                                                <thead>
                                                                    <tr className="text-gray-500 border-b border-gray-100">
                                                                        <th className="py-2">EasyEcom Main SKU</th>
                                                                        <th className="py-2">Item Name</th>
                                                                        <th className="py-2 text-right">MRP</th>
                                                                        <th className="py-2 text-right">Unit Cost (PO)</th>
                                                                        <th className="py-2 text-center">Price Check</th>
                                                                        <th className="py-2 text-right">Required Qty</th>
                                                                        <th className="py-2 text-right">Fulfillable Qty (FIFO)</th>
                                                                        <th className="py-2 text-center">Status</th>
                                                                    </tr>
                                                                </thead>
                                                                <tbody>
                                                                    {po.items.map((item, idx) => {
                                                                        const invItem = inventoryItems.find(i => i.articleCode === item.articleCode && i.channel === po.channel) 
                                                                                       || inventoryItems.find(i => i.articleCode === item.articleCode);

                                                                        // Use fulfillableQty directly from PO Item (calculated via FIFO in Sheet)
                                                                        const fulfillable = item.fulfillableQty !== undefined ? item.fulfillableQty : 0;
                                                                        const isShortage = fulfillable < item.qty;

                                                                        // Cost Check
                                                                        const priceStatus = item.priceCheckStatus?.toLowerCase() || 'unknown';
                                                                        const isCostMismatch = priceStatus !== 'ok' && priceStatus !== 'match' && priceStatus !== 'unknown';
                                                                        const isUnknown = priceStatus === 'unknown' || priceStatus === '';

                                                                        return (
                                                                            <tr key={idx} className={`border-b border-gray-50 ${isShortage || isCostMismatch ? 'bg-red-50' : ''}`}>
                                                                                <td className="py-2 font-medium text-gray-800">{item.masterSku || (invItem ? invItem.sku : '-')}</td>
                                                                                <td className="py-2 text-gray-600 truncate max-w-xs">{item.itemName || (invItem ? invItem.itemName : 'Item not found')}</td>
                                                                                <td className="py-2 text-right text-gray-600">₹{item.mrp?.toLocaleString('en-IN') || 0}</td>
                                                                                <td className="py-2 text-right text-gray-600">
                                                                                    ₹{item.unitCost?.toLocaleString('en-IN') || 0}
                                                                                </td>
                                                                                <td className="py-2 text-center">
                                                                                    {isCostMismatch ? (
                                                                                        <span className="text-red-600 font-bold bg-red-100 px-2 py-0.5 rounded text-[10px] uppercase">{item.priceCheckStatus}</span>
                                                                                    ) : isUnknown ? (
                                                                                        <span className="text-gray-400 italic text-[10px]">N/A</span>
                                                                                    ) : (
                                                                                        <span className="text-green-600 font-bold bg-green-100 px-2 py-0.5 rounded text-[10px] uppercase">OK</span>
                                                                                    )}
                                                                                </td>
                                                                                <td className="py-2 text-right font-medium text-gray-900">{item.qty}</td>
                                                                                <td className={`py-2 text-right font-bold ${isShortage ? 'text-red-600' : 'text-green-600'}`}>
                                                                                    {fulfillable}
                                                                                </td>
                                                                                <td className="py-2 text-center">
                                                                                    {isCostMismatch ? (
                                                                                        <span className="text-red-600 font-bold" title="Price Mismatch">Price Err</span>
                                                                                    ) : isShortage ? (
                                                                                        <span className="text-red-600 font-bold">Short</span>
                                                                                    ) : (
                                                                                        <span className="text-green-600">OK</span>
                                                                                    )}
                                                                                </td>
                                                                            </tr>
                                                                        );
                                                                    })}
                                                                </tbody>
                                                            </table>
                                                        )}
                                                        {hasCostError && (
                                                            <div className="mt-3 bg-red-100 text-red-700 p-2 rounded text-xs font-semibold text-center">
                                                                Action Blocked: One or more items have a price mismatch in the system.
                                                            </div>
                                                        )}
                                                    </div>
                                                </td>
                                            </tr>
                                        )}
                                    </Fragment>
                                    );
                                })
                            )}
                        </tbody>
                    </table>
                </div>
            </div>
        </>
    );
};

export default PoTable;
